import { request } from "./api";
import { LoginResponse } from "../types/api.types";

// Моковые пользователи для тестирования
let mockUsers = [
  { email: "test@test.com", password: "Test123!@", name: "Тест" },
  { email: "user@example.com", password: "User123!@", name: "Пользователь" },
];

// Определяем тип для данных пользователя
interface UserData {
  email: string;
  selectedCourses?: string[];
}

export const authService = {
  // Регистрация пользователя
  async register(
    email: string,
    password: string,
  ): Promise<{ message: string }> {
    try {
      // Пытаемся обратиться к реальному API
      return await request("/auth/register", {
        method: "POST",
        body: JSON.stringify({ email, password }),
      });
    } catch (error) {
      console.warn("API недоступен, используем моковую регистрацию:", error);

      // Проверяем, существует ли уже пользователь
      const existingUser = mockUsers.find((u) => u.email === email);
      if (existingUser) {
        throw new Error("Данная почта уже используется. Попробуйте войти.");
      }

      // Добавляем нового пользователя в моковый массив
      mockUsers.push({
        email,
        password,
        name: email.split("@")[0],
      });

      console.log("Моковые пользователи после регистрации:", mockUsers);
      return { message: "Регистрация прошла успешно!" };
    }
  },

  // Вход пользователя
  async login(email: string, password: string): Promise<LoginResponse> {
    try {
      // Пытаемся обратиться к реальному API
      return await request("/auth/login", {
        method: "POST",
        body: JSON.stringify({ email, password }),
      });
    } catch (error) {
      console.warn("API недоступен, используем моковый вход:", error);

      console.log("Проверка пользователя:", email, password);
      console.log("Доступные пользователи:", mockUsers);

      // Проверяем моковых пользователей
      const user = mockUsers.find((u) => u.email === email);

      if (!user) {
        console.log("Пользователь не найден");
        throw new Error("Пользователь с таким email не найден");
      }

      if (user.password !== password) {
        console.log("Неверный пароль");
        throw new Error("Неверный пароль");
      }

      console.log("Вход успешен");
      // Создаем фейковый токен
      const fakeToken = Buffer.from(
        JSON.stringify({
          email,
          exp: Date.now() + 7 * 24 * 60 * 60 * 1000,
        }),
      ).toString("base64");

      return { token: fakeToken };
    }
  },

  // Получение данных пользователя по токену
  async getUserData(token: string): Promise<{ user: UserData }> {
    try {
      return await request("/users/me", {
        method: "GET",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
    } catch (error) {
      console.warn(
        "API недоступен, используем моковые данные пользователя:",
        error,
      );

      // Декодируем фейковый токен
      try {
        const decoded = JSON.parse(Buffer.from(token, "base64").toString());
        return {
          user: {
            email: decoded.email,
            selectedCourses: ["1", "2", "3"], // Тестовые курсы
          },
        };
      } catch {
        throw new Error("Невалидный токен");
      }
    }
  },
};
